//! Deterministic mesh-gated face-to-face transfer.
//!
//! This is a classical image kernel: it warps a source face box into a target
//! face box, blends through an oval face matte fused with the target topology
//! mask, and emits a finite certificate. Detection, identity, perceptual
//! quality, and channel watermark recovery stay runtime obligations.

use serde::{Deserialize, Serialize};

use crate::mesh_residual_deblur::{mesh_residual_deblur_rgb_f32, MeshResidualDeblurConfig};
use crate::topology_mask::{build_topology_alpha, RgbLayout, TopologyAlphaConfig};

pub const FACE_TO_FACE_SWAP_VERSION: &str = "monster.face_to_face_swap.v1";
pub const FACE_TO_FACE_SWAP_V2_VERSION: &str = "monster.face_to_face_swap.v2";
pub const FACE_TO_FACE_SWAP_V3_VERSION: &str = "monster.face_to_face_swap.v3";

#[derive(Clone, Copy, Debug, Serialize, Deserialize, PartialEq)]
pub struct FaceSwapBox {
    pub x: f32,
    pub y: f32,
    pub w: f32,
    pub h: f32,
}

#[derive(Clone, Copy, Debug, Default, Serialize, Deserialize, PartialEq)]
pub struct FaceSwapLandmarks {
    pub left_eye: Option<(f32, f32)>,
    pub right_eye: Option<(f32, f32)>,
    pub mouth: Option<(f32, f32)>,
}

#[derive(Clone, Copy, Debug, Serialize, Deserialize, PartialEq)]
pub struct FaceSwapAnchor {
    pub x: f32,
    pub y: f32,
    pub role: u8,
    pub confidence: f32,
}

#[derive(Clone, Debug)]
pub struct FaceToFaceSwapConfig {
    pub blend_strength: f32,
    pub topology_blend: f32,
    pub admission_floor: f32,
    pub deblur_admission_blend: f32,
    pub topology: TopologyAlphaConfig,
    pub deblur: MeshResidualDeblurConfig,
}

impl Default for FaceToFaceSwapConfig {
    fn default() -> Self {
        Self {
            blend_strength: 0.82,
            topology_blend: 0.35,
            admission_floor: 0.12,
            deblur_admission_blend: 0.0,
            topology: TopologyAlphaConfig::default(),
            deblur: MeshResidualDeblurConfig::default(),
        }
    }
}

#[derive(Clone, Copy, Debug)]
pub struct FaceSwapV3Params {
    pub color_transfer_strength: f32,
    pub temporal_smoothing: f32,
    pub confidence_floor: f32,
    pub seam_correction: f32,
    /// Strength of the LOCAL "spill" refinement (non-rigid control-grid warp on
    /// top of the global micro-refine). 0 = off (rigid only). Kept low by
    /// default: a swap should seat features, not morph the source into the
    /// target's face shape.
    pub spill_strength: f32,
}

impl Default for FaceSwapV3Params {
    fn default() -> Self {
        Self {
            color_transfer_strength: 0.75,
            temporal_smoothing: 0.0,
            confidence_floor: 0.4,
            seam_correction: 0.6,
            spill_strength: 0.3,
        }
    }
}

/// Previous-frame target eye-bar state echoed by the client for temporal EMA:
/// `[mx / width, my / height, d / width, rot_radians, yaw]`.
pub type PrevTargetFrame = [f32; 5];

