#[derive(Clone, Debug, PartialEq)]
pub struct FaceToFaceSwapResult {
    pub rgb: Vec<f32>,
    pub alpha: Vec<f32>,
    pub certificate: FaceToFaceSwapCertificate,
}

fn clamp01(v: f32) -> f32 {
    v.clamp(0.0, 1.0)
}

fn round3(v: f32) -> f32 {
    (v * 1000.0).round() / 1000.0
}

fn face_coverage(face: FaceSwapBox, width: u32, height: u32) -> f32 {
    if width == 0 || height == 0 {
        return 0.0;
    }
    let area = face.w.max(0.0) * face.h.max(0.0);
    clamp01(area / ((width as f32) * (height as f32)))
}

fn valid_face_box(face: FaceSwapBox, width: u32, height: u32) -> bool {
    face.w >= 2.0
        && face.h >= 2.0
        && face.x.is_finite()
        && face.y.is_finite()
        && face.w.is_finite()
        && face.h.is_finite()
        && face.x + face.w > 0.0
        && face.y + face.h > 0.0
        && face.x < width as f32
        && face.y < height as f32
}

fn sample_bilinear(rgb: &[f32], width: usize, height: usize, x: f32, y: f32, c: usize) -> f32 {
    let fx = x.clamp(0.0, (width.saturating_sub(1)) as f32);
    let fy = y.clamp(0.0, (height.saturating_sub(1)) as f32);
    let x0 = fx.floor() as usize;
    let y0 = fy.floor() as usize;
    let x1 = (x0 + 1).min(width.saturating_sub(1));
    let y1 = (y0 + 1).min(height.saturating_sub(1));
    let tx = fx - x0 as f32;
    let ty = fy - y0 as f32;
    let p00 = rgb[(y0 * width + x0) * 3 + c];
    let p10 = rgb[(y0 * width + x1) * 3 + c];
    let p01 = rgb[(y1 * width + x0) * 3 + c];
    let p11 = rgb[(y1 * width + x1) * 3 + c];
    let a = p00 * (1.0 - tx) + p10 * tx;
    let b = p01 * (1.0 - tx) + p11 * tx;
    a * (1.0 - ty) + b * ty
}

/// Eye-bar face frame: all geometry keys off the interocular segment.
/// Origin `m` = eye midpoint, `e` = unit left→right eye vector, `d` =
/// interocular distance (pixels). `n` (downward perpendicular, y-down image
/// coords) is `(-e.1, e.0)` rotated so the face body lies on its positive side.
#[derive(Clone, Copy, Debug)]
struct EyeBarFrame {
    mx: f32,
    my: f32,
    ex: f32,
    ey: f32,
    d: f32,
    /// Nose offset along the eye bar over half the interocular distance,
    /// clamped to [-1, 1]. Sign points at the occluded half of the face.
    yaw: f32,
    conf: f32,
}

impl EyeBarFrame {
    fn nx(&self) -> f32 {
        -self.ey
    }
    fn ny(&self) -> f32 {
        self.ex
    }
    fn rot(&self) -> f32 {
        self.ey.atan2(self.ex)
    }
    /// Matte center: eye midpoint pushed down the face by k interocular units.
    fn center(&self, k: f32) -> (f32, f32) {
        (self.mx + self.nx() * self.d * k, self.my + self.ny() * self.d * k)
    }
}

// Matte centre offset + radii in units of interocular distance `d`. The vertical
// pair was tuned against the OLD detector's eyes, which sat high (forehead), so a
// big downward reach (0.58 + 1.80 = 2.38·d below the eyes) was needed to cover the
// face. With correctly-placed eyes (hint mode / improved detection) that reach
// lands on the neck/chest, so it's tightened to hug the real face: hairline
// (≈0.85·d above the eyes) to just past the chin (≈1.35·d below).
const EYE_BAR_CENTER_K: f32 = 0.15;
const EYE_BAR_RX: f32 = 1.05;
const EYE_BAR_RY: f32 = 1.20;
const EYE_BAR_CONF_FLOOR: f32 = 0.30;

fn best_anchor_for_role(anchors: &[FaceSwapAnchor], role: u8) -> Option<(f32, f32, f32)> {
    let mut best: Option<(f32, f32, f32)> = None;
    for anchor in anchors {
        if anchor.role != role || !anchor.x.is_finite() || !anchor.y.is_finite() {
            continue;
        }
        let conf = anchor.confidence.clamp(0.0, 1.0);
        if best.map(|b| conf > b.2).unwrap_or(true) {
            best = Some((anchor.x, anchor.y, conf));
        }
    }
    best
}

fn eye_bar_frame(anchors: &[FaceSwapAnchor]) -> Option<EyeBarFrame> {
    let (lx, ly, lc) = best_anchor_for_role(anchors, 0)?;
    let (rx, ry, rc) = best_anchor_for_role(anchors, 1)?;
    let dx = rx - lx;
    let dy = ry - ly;
    let d = (dx * dx + dy * dy).sqrt();
    if !d.is_finite() || d < 2.0 {
        return None;
    }
    let ex = dx / d;
    let ey = dy / d;
    let mx = (lx + rx) * 0.5;
    let my = (ly + ry) * 0.5;
    let mut yaw = 0.0_f32;
    if let Some((nx, ny, nc)) = best_anchor_for_role(anchors, 2) {
        if nc >= 0.3 {
            let off = ((nx - mx) * ex + (ny - my) * ey) / (0.5 * d);
            if off.is_finite() {
                yaw = off.clamp(-1.0, 1.0);
            }
        }
    }
    Some(EyeBarFrame { mx, my, ex, ey, d, yaw, conf: (lc * rc).sqrt().clamp(0.0, 1.0) })
}

/// Rotated elliptical matte in eye-bar coordinates, with a yaw-aware
/// visibility gate that fades the occluded half of a turned face (the side
/// the nose points toward). Detector boxes play no part here.
fn eye_bar_matte(px: f32, py: f32, frame: &EyeBarFrame) -> f32 {
    let (cx, cy) = frame.center(EYE_BAR_CENTER_K);
    let dx = px - cx;
    let dy = py - cy;
    let xi = (dx * frame.ex + dy * frame.ey) / (EYE_BAR_RX * frame.d).max(1e-3);
    let eta = (dx * frame.nx() + dy * frame.ny()) / (EYE_BAR_RY * frame.d).max(1e-3);
    let e = xi * xi + eta * eta;
    if e >= 1.0 {
        return 0.0;
    }
    let base = (1.0 - e).max(0.0).sqrt() * (1.0 - smoothstep(0.78, 1.0, e));
    base * half_face_visibility(xi, frame.yaw)
}

/// Visibility of a face point at eye-bar coordinate `xi` (unit = matte rx,
/// positive toward the right eye) for a head turned by yaw. The occluded half
/// sits past the nose line on the side the nose points toward; by |yaw| ~ 0.6
/// (a true half-turn) that half is fully suppressed.
fn half_face_visibility(xi: f32, yaw: f32) -> f32 {
    let profile_amount = smoothstep(0.15, 0.6, yaw.abs());
    if profile_amount <= 0.0 {
        return 1.0;
    }
    let occluded_coord = xi * yaw.signum();
    (1.0 - smoothstep(0.0, 0.65, occluded_coord) * profile_amount).clamp(0.0, 1.0)
}

/// Conservative pixel bounding box of the eye-bar matte, clipped to the image
/// AND to the detected `face` box (expanded by a feather margin). The face-box
/// intersection is the amplifier guard: if the eye anchors are bad (e.g. landed
/// on the hairline) the raw ellipse can reach `1.22·d` above the bar into hair
/// and scale `~d²` into a head-slab; the painted region can never legitimately
/// exceed the detected face, so we crop it there. Box-independent-safe: it only
/// ever *shrinks* the region, so a loose full-frame box simply doesn't clip.
fn eye_bar_bounds(
    frame: &EyeBarFrame,
    width: usize,
    height: usize,
    face: FaceSwapBox,
) -> (usize, usize, usize, usize) {
    let (cx, cy) = frame.center(EYE_BAR_CENTER_K);
    let rx = EYE_BAR_RX * frame.d;
    let ry = EYE_BAR_RY * frame.d;
    let hx = rx * frame.ex.abs() + ry * frame.nx().abs();
    let hy = rx * frame.ey.abs() + ry * frame.ny().abs();
    // Face box expanded by a feather margin so a correctly-placed matte keeps
    // its soft edge but a runaway slab is cropped to the face.
    let mx = face.w * 0.15;
    let my = face.h * 0.15;
    let fx0 = (face.x - mx).max(0.0);
    let fy0 = (face.y - my).max(0.0);
    let fx1 = (face.x + face.w + mx).max(0.0);
    let fy1 = (face.y + face.h + my).max(0.0);
    let min_x = (cx - hx).floor().max(fx0) as usize;
    let min_y = (cy - hy).floor().max(fy0) as usize;
    let max_x = ((cx + hx).ceil().min(fx1).max(0.0) as usize).min(width);
    let max_y = ((cy + hy).ceil().min(fy1).max(0.0) as usize).min(height);
    // Guard against an inverted range if the matte sits entirely outside the box.
    let max_x = max_x.max(min_x);
    let max_y = max_y.max(min_y);
    (min_x, min_y, max_x, max_y)
}

/// Per-channel mean and standard deviation over the face core. Uses the inner
/// eye-bar ellipse (e <= 0.7) when the frame is trustworthy so color statistics
/// never sample collar or chest pixels from a loose detector box; otherwise
/// falls back to the legacy detector-box oval.
fn face_stats_rgb(
    rgb: &[f32],
    width: usize,
    height: usize,
    face: FaceSwapBox,
    frame: Option<&EyeBarFrame>,
) -> ([f32; 3], [f32; 3]) {
    let mut sum = [0.0_f32; 3];
    let mut sq = [0.0_f32; 3];
    let mut n = 0.0_f32;
    let mut accumulate = |o: usize| {
        for c in 0..3 {
            let v = rgb[o + c];
            sum[c] += v;
            sq[c] += v * v;
        }
        n += 1.0;
    };
    match frame {
        Some(frame) if frame.conf >= EYE_BAR_CONF_FLOOR => {
            let (min_x, min_y, max_x, max_y) = eye_bar_bounds(frame, width, height, face);
            let (cx, cy) = frame.center(EYE_BAR_CENTER_K);
            for y in min_y..max_y {
                for x in min_x..max_x {
                    let px = x as f32 + 0.5;
                    let py = y as f32 + 0.5;
                    let dx = px - cx;
                    let dy = py - cy;
                    let xi = (dx * frame.ex + dy * frame.ey) / (EYE_BAR_RX * frame.d).max(1e-3);
                    let eta = (dx * frame.nx() + dy * frame.ny()) / (EYE_BAR_RY * frame.d).max(1e-3);
                    if xi * xi + eta * eta > 0.7 {
                        continue;
                    }
                    accumulate((y * width + x) * 3);
                }
            }
        }
        _ => {
            let min_x = face.x.floor().max(0.0) as usize;
            let min_y = face.y.floor().max(0.0) as usize;
            let max_x = (face.x + face.w).ceil().min(width as f32).max(0.0) as usize;
            let max_y = (face.y + face.h).ceil().min(height as f32).max(0.0) as usize;
            for y in min_y..max_y {
                for x in min_x..max_x {
                    let u = ((x as f32 + 0.5) - face.x) / face.w.max(1.0);
                    let v = ((y as f32 + 0.5) - face.y) / face.h.max(1.0);
                    let dx = (u - 0.5) / 0.5;
                    let dy = (v - 0.47) / 0.58;
                    if dx * dx + dy * dy > 1.0 {
                        continue;
                    }
                    accumulate((y * width + x) * 3);
                }
            }
        }
    }
    if n <= 0.0 {
        return ([0.0; 3], [0.0; 3]);
    }
    let mean = [sum[0] / n, sum[1] / n, sum[2] / n];
    let std = [
        (sq[0] / n - mean[0] * mean[0]).max(0.0).sqrt(),
        (sq[1] / n - mean[1] * mean[1]).max(0.0).sqrt(),
        (sq[2] / n - mean[2] * mean[2]).max(0.0).sqrt(),
    ];
    (mean, std)
}

fn landmark_eye_tilt(landmarks: FaceSwapLandmarks) -> f32 {
    match (landmarks.left_eye, landmarks.right_eye) {
        (Some((lx, ly)), Some((rx, ry))) if (rx - lx).abs() > 1e-3 => (ry - ly) / (rx - lx),
        _ => 0.0,
    }
}

fn legacy_anchors(face: FaceSwapBox, landmarks: FaceSwapLandmarks) -> Vec<FaceSwapAnchor> {
    let left_eye = landmarks
        .left_eye
        .unwrap_or((face.x + face.w * 0.33, face.y + face.h * 0.35));
    let right_eye = landmarks
        .right_eye
        .unwrap_or((face.x + face.w * 0.67, face.y + face.h * 0.35));
    // Synthesize nose/chin from the EYE MIDPOINT + interocular distance `d`, NOT
    // the face-BOX height. Box-fraction anchors (0.51·h, 0.91·h) land at different
    // face-relative positions when the source and target boxes have different
    // proportions (a tall source box puts them on the neck/collar), so the
    // similarity fit skewed the lower face DOWN — "neck on eyes". d-relative
    // offsets are box-independent and match the eye-bar matte's face-hugging
    // convention (nose ~0.5·d, mouth ~0.95·d, chin ~1.35·d below the eyes).
    let dx = right_eye.0 - left_eye.0;
    let dy = right_eye.1 - left_eye.1;
    let d = (dx * dx + dy * dy).sqrt().max(1.0);
    let mid_x = (left_eye.0 + right_eye.0) * 0.5;
    let mid_y = (left_eye.1 + right_eye.1) * 0.5;
    let mouth = landmarks.mouth.unwrap_or((mid_x, mid_y + d * 0.95));
    vec![
        FaceSwapAnchor { x: left_eye.0, y: left_eye.1, role: 0, confidence: 0.8 },
        FaceSwapAnchor { x: right_eye.0, y: right_eye.1, role: 1, confidence: 0.8 },
        FaceSwapAnchor { x: mid_x, y: mid_y + d * 0.5, role: 2, confidence: 0.55 },
        FaceSwapAnchor { x: mouth.0, y: mouth.1, role: 3, confidence: 0.55 },
        FaceSwapAnchor { x: mid_x, y: mid_y + d * 1.35, role: 6, confidence: 0.45 },
    ]
}

fn normalized_anchor(anchor: FaceSwapAnchor, face: FaceSwapBox) -> Option<(f32, f32, u8, f32)> {
    if !anchor.x.is_finite() || !anchor.y.is_finite() || !anchor.confidence.is_finite() {
        return None;
    }
    let u = (anchor.x - face.x) / face.w.max(1.0);
    let v = (anchor.y - face.y) / face.h.max(1.0);
    if !u.is_finite() || !v.is_finite() {
        return None;
    }
    Some((u, v, anchor.role, anchor.confidence.clamp(0.0, 1.0)))
}

fn source_anchor_for_role(
    source_anchors: &[FaceSwapAnchor],
    source_face: FaceSwapBox,
    role: u8,
) -> Option<(f32, f32, f32)> {
    let mut best: Option<(f32, f32, f32)> = None;
    for anchor in source_anchors {
        if anchor.role != role {
            continue;
        }
        if let Some((u, v, _, conf)) = normalized_anchor(*anchor, source_face) {
            if best.map(|b| conf > b.2).unwrap_or(true) {
                best = Some((u, v, conf));
            }
        }
    }
    best
}

fn normalized_anchor_for_role(
    anchors: &[FaceSwapAnchor],
    face: FaceSwapBox,
    role: u8,
) -> Option<(f32, f32, f32)> {
    source_anchor_for_role(anchors, face, role)
}

#[derive(Clone, Copy, Debug)]
struct AnchorFaceFrame {
    cx: f32,
    cy: f32,
    rx: f32,
    ry: f32,
    confidence: f32,
}

fn anchor_face_frame(anchors: &[FaceSwapAnchor], face: FaceSwapBox) -> AnchorFaceFrame {
    let left_eye = normalized_anchor_for_role(anchors, face, 0);
    let right_eye = normalized_anchor_for_role(anchors, face, 1);
    let nose = normalized_anchor_for_role(anchors, face, 2);
    let mouth = normalized_anchor_for_role(anchors, face, 3);
    let chin = normalized_anchor_for_role(anchors, face, 6);

    let (eye_mid_u, eye_mid_v, eye_dist, eye_conf) = match (left_eye, right_eye) {
        (Some((lu, lv, lc)), Some((ru, rv, rc))) => {
            let dx = ru - lu;
            let dy = rv - lv;
            (
                (lu + ru) * 0.5,
                (lv + rv) * 0.5,
                (dx * dx + dy * dy).sqrt().clamp(0.12, 0.7),
                (lc * rc).sqrt().clamp(0.0, 1.0),
            )
        }
        _ => (0.5, 0.35, 0.34, 0.25),
    };

    let (mouth_u, mouth_v, mouth_conf) = mouth.unwrap_or((0.5, 0.69, 0.25));
    let (_chin_u, chin_v, chin_conf) = chin.unwrap_or((0.5, 0.91, 0.15));
    let (nose_u, nose_v, nose_conf) = nose.unwrap_or((eye_mid_u, eye_mid_v * 0.45 + mouth_v * 0.55, 0.2));
    let lower_v = if chin_conf >= 0.25 { chin_v } else { mouth_v + (mouth_v - eye_mid_v) * 0.72 };
    let vertical_span = (lower_v - eye_mid_v).abs().clamp(0.24, 0.82);
    let rx = (eye_dist * 1.52).clamp(0.28, 0.72);
    let ry = (vertical_span * 0.78).clamp(0.32, 0.82);
    let cx = (nose_u * (0.55 + nose_conf * 0.25) + eye_mid_u * 0.3 + mouth_u * 0.15)
        .clamp(0.22, 0.78);
    let cy = (nose_v * 0.2 + eye_mid_v * 0.18 + lower_v * 0.44 + mouth_v * 0.18)
        .clamp(0.28, 0.72);
    let confidence = ((eye_conf * 0.55) + (mouth_conf * 0.25) + (chin_conf * 0.1) + (nose_conf * 0.1))
        .clamp(0.0, 1.0);

    AnchorFaceFrame { cx, cy, rx, ry, confidence }
}

fn anchor_aligned_uv(
    u: f32,
    v: f32,
    source_frame: AnchorFaceFrame,
    target_frame: AnchorFaceFrame,
) -> (f32, f32, f32) {
    let support = (source_frame.confidence * target_frame.confidence).sqrt().clamp(0.0, 1.0);
    if support < 0.18 {
        return (u, v, 0.0);
    }
    let rel_u = (u - target_frame.cx) / target_frame.rx.max(1e-3);
    let rel_v = (v - target_frame.cy) / target_frame.ry.max(1e-3);
    (
        (source_frame.cx + rel_u * source_frame.rx).clamp(-0.12, 1.12),
        (source_frame.cy + rel_v * source_frame.ry).clamp(-0.12, 1.12),
        support,
    )
}

fn anchor_warp_uv(
    u: f32,
    v: f32,
    source_face: FaceSwapBox,
    target_face: FaceSwapBox,
    source_anchors: &[FaceSwapAnchor],
    target_anchors: &[FaceSwapAnchor],
) -> (f32, f32, f32) {
    let mut du_sum = 0.0_f32;
    let mut dv_sum = 0.0_f32;
    let mut weight_sum = 0.0_f32;
    let mut pairs = 0.0_f32;
    for target_anchor in target_anchors {
        let Some((tu, tv, role, tconf)) = normalized_anchor(*target_anchor, target_face) else {
            continue;
        };
        let Some((su, sv, sconf)) = source_anchor_for_role(source_anchors, source_face, role) else {
            continue;
        };
        let dx = u - tu;
        let dy = v - tv;
        let local = 1.0 / (0.018 + dx * dx + dy * dy);
        let confidence = (tconf * sconf).sqrt().clamp(0.0, 1.0);
        let role_weight = match role {
            0 | 1 => 1.35,
            2 | 3 | 4 | 5 => 1.15,
            _ => 0.72,
        };
        let weight = local * confidence * role_weight;
        du_sum += (su - tu) * weight;
        dv_sum += (sv - tv) * weight;
        weight_sum += weight;
        pairs += confidence;
    }
    if weight_sum <= 0.0 {
        return (u, v, 0.0);
    }
    let strength = (weight_sum / (weight_sum + 45.0)).clamp(0.0, 0.78);
    (
        (u + du_sum / weight_sum * strength).clamp(-0.08, 1.08),
        (v + dv_sum / weight_sum * strength).clamp(-0.08, 1.08),
        (pairs / target_anchors.len().max(1) as f32).clamp(0.0, 1.0),
    )
}

fn smoothstep(edge0: f32, edge1: f32, x: f32) -> f32 {
    let t = ((x - edge0) / (edge1 - edge0).max(1e-6)).clamp(0.0, 1.0);
    t * t * (3.0 - 2.0 * t)
}

fn similarity_role_weight(role: u8) -> f32 {
    match role {
        0 | 1 => 1.35,
        2 | 3 | 4 | 5 => 1.15,
        6 => 0.9,
        _ => 0.0,
    }
}

/// Weighted reflection-free 2D similarity, target pixels -> source pixels:
/// `q = mu_s + [[a, -b], [b, a]] * (p - mu_t)`.
#[derive(Clone, Copy, Debug)]
pub(crate) struct SimilarityMap {
    mu_tx: f32,
    mu_ty: f32,
    mu_sx: f32,
    mu_sy: f32,
    a: f32,
    b: f32,
    pub(crate) confidence: f32,
}

impl SimilarityMap {
    pub(crate) fn apply(&self, px: f32, py: f32) -> (f32, f32) {
        let dx = px - self.mu_tx;
        let dy = py - self.mu_ty;
        (self.mu_sx + self.a * dx - self.b * dy, self.mu_sy + self.b * dx + self.a * dy)
    }
    pub(crate) fn scale(&self) -> f32 {
        (self.a * self.a + self.b * self.b).sqrt()
    }
    pub(crate) fn rotation(&self) -> f32 {
        self.b.atan2(self.a)
    }
}

/// Closed-form weighted least-squares similarity over role-matched anchor
/// correspondences. Eyes are mandatory: the eye bar is the backbone, other
/// observed anchors only refine it. With eyes alone this is exactly the
/// eye-bar transform (rotate-align the bar, scale by interocular ratio).
pub(crate) fn fit_similarity(
    source_anchors: &[FaceSwapAnchor],
    target_anchors: &[FaceSwapAnchor],
    confidence_floor: f32,
    reference_spread: f32,
) -> Option<SimilarityMap> {
    let mut pairs: Vec<(f32, f32, f32, f32, f32)> = Vec::new();
    let mut has_left_eye = false;
    let mut has_right_eye = false;
    for role in [0_u8, 1, 2, 3, 4, 5, 6] {
        let role_weight = similarity_role_weight(role);
        if role_weight <= 0.0 {
            continue;
        }
        let Some((tx, ty, tc)) = best_anchor_for_role(target_anchors, role) else {
            continue;
        };
        let Some((sx, sy, sc)) = best_anchor_for_role(source_anchors, role) else {
            continue;
        };
        if tc < confidence_floor || sc < confidence_floor {
            continue;
        }
        if role == 0 {
            has_left_eye = true;
        }
        if role == 1 {
            has_right_eye = true;
        }
        let w = (sc * tc).sqrt() * role_weight;
        pairs.push((tx, ty, sx, sy, w));
    }
    if pairs.len() < 2 || !has_left_eye || !has_right_eye {
        return None;
    }
    let w_total: f32 = pairs.iter().map(|p| p.4).sum();
    if w_total < 0.8 {
        return None;
    }
    let mu_tx = pairs.iter().map(|p| p.0 * p.4).sum::<f32>() / w_total;
    let mu_ty = pairs.iter().map(|p| p.1 * p.4).sum::<f32>() / w_total;
    let mu_sx = pairs.iter().map(|p| p.2 * p.4).sum::<f32>() / w_total;
    let mu_sy = pairs.iter().map(|p| p.3 * p.4).sum::<f32>() / w_total;
    let mut d = 0.0_f32;
    let mut a_num = 0.0_f32;
    let mut b_num = 0.0_f32;
    let mut max_spread = 0.0_f32;
    for (tx, ty, sx, sy, w) in &pairs {
        let tx = tx - mu_tx;
        let ty = ty - mu_ty;
        let sx = sx - mu_sx;
        let sy = sy - mu_sy;
        d += w * (tx * tx + ty * ty);
        a_num += w * (sx * tx + sy * ty);
        b_num += w * (sy * tx - sx * ty);
        max_spread = max_spread.max((tx * tx + ty * ty).sqrt());
    }
    if d <= 1e-6 || max_spread < reference_spread {
        return None;
    }
    let mut a = a_num / d;
    let mut b = b_num / d;
    let scale = (a * a + b * b).sqrt();
    if !scale.is_finite() || scale <= 1e-4 {
        return None;
    }
    // Bounds guard against numerical blowup from degenerate anchors, NOT a
    // plausibility window on real face sizes: source and target photos
    // routinely differ by an order of magnitude in interocular pixel
    // distance (a small reference photo vs. a zoomed-in capture frame), and
    // the fit above already derives its scale directly from real matched
    // eye/nose/mouth pixel positions. A narrow absolute clamp here (this
    // used to be `scale.clamp(0.5, 2.2)`) silently overrode a CORRECT,
    // anchor-derived scale with a wrong one whenever the true ratio fell
    // outside that band, so every point below the eye line sampled too far
    // down in the source (onto the neck/collar) even with perfectly
    // accurate eye landmarks -- the `max_spread < reference_spread` guard
    // above already rejects degenerate/noisy fits, so this only needs to
    // catch true blowups, not legitimate size mismatches.
    let clamped_scale = scale.clamp(0.05, 20.0);
    // Rotation guard against wild AUTO-detect anchor flips, NOT a plausibility
    // window on real head roll. Source and target heads routinely tilt in
    // OPPOSITE directions (e.g. source +20 deg, target -20 deg needs a 40 deg
    // source rotation to align the eye bars); a narrow clamp (this used to be
    // 0.55 rad = 31.5 deg) silently under-rotated those pairs, leaving the swap
    // visibly misaligned. Widened to ~57 deg so honest opposite tilts rotate
    // fully while true blowups (near-180 deg flips from bad anchors) are still
    // caught. The `max_spread < reference_spread` guard above already rejects
    // degenerate fits, so this only needs to bound gross flips.
    const MAX_ROLL: f32 = 1.0; // radians (~57.3 deg)
    let mut theta = b.atan2(a);
    if theta.abs() > MAX_ROLL {
        theta = MAX_ROLL * theta.signum();
    }
    if (clamped_scale - scale).abs() > 1e-6 || theta != b.atan2(a) {
        a = clamped_scale * theta.cos();
        b = clamped_scale * theta.sin();
    }
    let confidence = (w_total / (w_total + 1.6)).clamp(0.0, 1.0);
    Some(SimilarityMap { mu_tx, mu_ty, mu_sx, mu_sy, a, b, confidence })
}

/// Smooth non-rigid "spill" displacement field: a coarse `nx*ny` control grid of
/// source-pixel offsets over the target face box, bilinearly interpolated and
/// scaled by `strength`. Added on TOP of the global similarity, it lets the
/// correction go local — seating features where the two faces disagree while
/// leaving matched regions alone.
#[derive(Clone, Debug)]
struct SpillField {
    nx: usize,
    ny: usize,
    face: FaceSwapBox,
    dx: Vec<f32>,
    dy: Vec<f32>,
    strength: f32,
}

impl SpillField {
    /// Interpolated source-pixel offset at target pixel `(px, py)`, scaled by
    /// `strength`. Zero outside the face box (clamped to the border grid value).
    fn sample(&self, px: f32, py: f32) -> (f32, f32) {
        let u = ((px - self.face.x) / self.face.w.max(1.0)).clamp(0.0, 1.0);
        let v = ((py - self.face.y) / self.face.h.max(1.0)).clamp(0.0, 1.0);
        let gx = u * (self.nx.saturating_sub(1)) as f32;
        let gy = v * (self.ny.saturating_sub(1)) as f32;
        let x0 = gx.floor() as usize;
        let y0 = gy.floor() as usize;
        let x1 = (x0 + 1).min(self.nx - 1);
        let y1 = (y0 + 1).min(self.ny - 1);
        let tx = gx - x0 as f32;
        let ty = gy - y0 as f32;
        let at = |arr: &[f32], x: usize, y: usize| arr[y * self.nx + x];
        let lerp = |a: f32, b: f32, t: f32| a * (1.0 - t) + b * t;
        let ddx = lerp(
            lerp(at(&self.dx, x0, y0), at(&self.dx, x1, y0), tx),
            lerp(at(&self.dx, x0, y1), at(&self.dx, x1, y1), tx),
            ty,
        );
        let ddy = lerp(
            lerp(at(&self.dy, x0, y0), at(&self.dy, x1, y0), tx),
            lerp(at(&self.dy, x0, y1), at(&self.dy, x1, y1), tx),
            ty,
        );
        (ddx * self.strength, ddy * self.strength)
    }

    /// Largest interpolated displacement magnitude actually applied (post-scale).
    fn max_disp(&self) -> f32 {
        let mut m = 0.0_f32;
        for i in 0..self.dx.len() {
            m = m.max((self.dx[i] * self.dx[i] + self.dy[i] * self.dy[i]).sqrt());
        }
        m * self.strength
    }
}

/// Luma gradient magnitude at a sub-pixel point (central differences). Gradient
/// MAGNITUDE is orientation-free, so it correlates facial STRUCTURE (eye corners,
/// nostrils, lip line, jaw edges) across two different faces regardless of their
/// color, lighting, or relative rotation.
fn grad_mag(rgb: &[f32], w: usize, h: usize, x: f32, y: f32) -> f32 {
    let luma = |xx: f32, yy: f32| -> f32 {
        (sample_bilinear(rgb, w, h, xx, yy, 0)
            + sample_bilinear(rgb, w, h, xx, yy, 1)
            + sample_bilinear(rgb, w, h, xx, yy, 2))
            * (1.0 / 3.0)
    };
    let gx = luma(x + 1.0, y) - luma(x - 1.0, y);
    let gy = luma(x, y + 1.0) - luma(x, y - 1.0);
    (gx * gx + gy * gy).sqrt()
}

/// Normalized cross-correlation of target vs warped-source gradient magnitude
/// over a grid on the target face box. Higher = better structural registration.
/// `NEG_INFINITY` when too few in-bounds samples to be meaningful.
#[allow(clippy::too_many_arguments)]
fn structure_ncc(
    sim: &SimilarityMap,
    spill: Option<&SpillField>,
    source_rgb: &[f32],
    sw: usize,
    sh: usize,
    target_rgb: &[f32],
    tw: usize,
    th: usize,
    face: FaceSwapBox,
    grid: usize,
) -> f32 {
    let mut ts: Vec<f32> = Vec::with_capacity(grid * grid);
    let mut ss: Vec<f32> = Vec::with_capacity(grid * grid);
    for gy in 0..grid {
        for gx in 0..grid {
            let u = (gx as f32 + 0.5) / grid as f32;
            let v = (gy as f32 + 0.5) / grid as f32;
            let px = face.x + u * face.w;
            let py = face.y + v * face.h;
            let (mut qx, mut qy) = sim.apply(px, py);
            if let Some(f) = spill {
                let (sx, sy) = f.sample(px, py);
                qx += sx;
                qy += sy;
            }
            if qx < 1.0 || qy < 1.0 || qx >= (sw - 1) as f32 || qy >= (sh - 1) as f32 {
                continue;
            }
            ts.push(grad_mag(target_rgb, tw, th, px, py));
            ss.push(grad_mag(source_rgb, sw, sh, qx, qy));
        }
    }
    if ts.len() < 16 {
        return f32::NEG_INFINITY;
    }
    let n = ts.len() as f32;
    let mt = ts.iter().sum::<f32>() / n;
    let ms = ss.iter().sum::<f32>() / n;
    let (mut cov, mut vt, mut vs) = (0.0_f32, 0.0_f32, 0.0_f32);
    for i in 0..ts.len() {
        let dt = ts[i] - mt;
        let ds = ss[i] - ms;
        cov += dt * ds;
        vt += dt * dt;
        vs += ds * ds;
    }
    let denom = (vt * vs).sqrt();
    if denom < 1e-6 {
        0.0
    } else {
        cov / denom
    }
}

/// Local "vibrating" refinement of the coarse eye-anchored similarity. Perturbs
/// (rotation, scale, translation) by a shrinking step (the vibration, annealed by
/// halving) and keeps whatever raises `structure_ncc`. Bounded to SMALL
/// corrections vs the original fit so it refines rather than wanders, and gated:
/// returns the ORIGINAL map with gain 0 if nothing beats the coarse fit — it can
/// never make alignment worse. `d` = target interocular (bounds the translation).
#[allow(clippy::too_many_arguments)]
fn micro_refine(
    sim: SimilarityMap,
    source_rgb: &[f32],
    sw: usize,
    sh: usize,
    target_rgb: &[f32],
    tw: usize,
    th: usize,
    face: FaceSwapBox,
    d: f32,
) -> (SimilarityMap, f32) {
    const GRID: usize = 24;
    if sw < 3 || sh < 3 || face.w < 4.0 || face.h < 4.0 {
        return (sim, 0.0);
    }
    let base = structure_ncc(&sim, None, source_rgb, sw, sh, target_rgb, tw, th, face, GRID);
    if !base.is_finite() {
        return (sim, 0.0);
    }
    let d = d.max(1.0);
    let scale0 = sim.scale();
    let theta0 = sim.rotation();
    let build = |theta: f32, scale: f32, tx: f32, ty: f32| SimilarityMap {
        mu_tx: sim.mu_tx,
        mu_ty: sim.mu_ty,
        mu_sx: tx,
        mu_sy: ty,
        a: scale * theta.cos(),
        b: scale * theta.sin(),
        confidence: sim.confidence,
    };
    // Bounds vs the original coarse fit: rotation ±0.13 rad (~7.5 deg), scale
    // ±12 %, translation ±0.18 interocular. A refinement, not a re-solve.
    let in_bounds = |theta: f32, scale: f32, tx: f32, ty: f32| -> bool {
        (theta - theta0).abs() <= 0.13
            && (scale / scale0 - 1.0).abs() <= 0.12
            && (tx - sim.mu_sx).abs() <= 0.18 * d
            && (ty - sim.mu_sy).abs() <= 0.18 * d
    };
    let (mut theta, mut scale, mut tx, mut ty) = (theta0, scale0, sim.mu_sx, sim.mu_sy);
    let mut best = base;
    let (mut s_theta, mut s_scale, mut s_trans) = (0.04_f32, 0.04_f32, 0.06_f32 * d);
    for _ in 0..48 {
        let candidates: [(f32, f32, f32, f32); 8] = [
            (theta + s_theta, scale, tx, ty),
            (theta - s_theta, scale, tx, ty),
            (theta, scale * (1.0 + s_scale), tx, ty),
            (theta, scale * (1.0 - s_scale), tx, ty),
            (theta, scale, tx + s_trans, ty),
            (theta, scale, tx - s_trans, ty),
            (theta, scale, tx, ty + s_trans),
            (theta, scale, tx, ty - s_trans),
        ];
        let mut best_move: Option<(f32, f32, f32, f32, f32)> = None;
        for &(t, sc, x, y) in candidates.iter() {
            if !in_bounds(t, sc, x, y) {
                continue;
            }
            let cand = build(t, sc, x, y);
            let ncc = structure_ncc(&cand, None, source_rgb, sw, sh, target_rgb, tw, th, face, GRID);
            if ncc > best_move.map(|m| m.4).unwrap_or(best) {
                best_move = Some((t, sc, x, y, ncc));
            }
        }
        if let Some((t, sc, x, y, ncc)) = best_move {
            theta = t;
            scale = sc;
            tx = x;
            ty = y;
            best = ncc;
        } else {
            // No improving move at this step: vibrate smaller.
            s_theta *= 0.5;
            s_scale *= 0.5;
            s_trans *= 0.5;
            if s_theta < 0.003 && s_scale < 0.003 && s_trans < 0.02 * d {
                break;
            }
        }
    }
    let gain = best - base;
    if gain > 1e-4 {
        (build(theta, scale, tx, ty), gain)
    } else {
        (sim, 0.0)
    }
}

/// Best small source-pixel translation `(dx, dy)` that maximizes gradient-NCC in
/// a window around target point `(cx, cy)`, bounded to `±max_disp`. Coordinate
/// descent with an annealing step — the per-cell "vibration".
#[allow(clippy::too_many_arguments)]
fn fit_local_offset(
    sim: &SimilarityMap,
    source_rgb: &[f32],
    sw: usize,
    sh: usize,
    target_rgb: &[f32],
    tw: usize,
    th: usize,
    cx: f32,
    cy: f32,
    half_x: f32,
    half_y: f32,
    max_disp: f32,
) -> (f32, f32) {
    const G: usize = 9;
    let score = |dx: f32, dy: f32| -> f32 {
        let mut ts = [0.0f32; G * G];
        let mut ss = [0.0f32; G * G];
        let mut n = 0usize;
        for gy in 0..G {
            for gx in 0..G {
                let px = cx - half_x + (gx as f32 + 0.5) / G as f32 * 2.0 * half_x;
                let py = cy - half_y + (gy as f32 + 0.5) / G as f32 * 2.0 * half_y;
                let (mut qx, mut qy) = sim.apply(px, py);
                qx += dx;
                qy += dy;
                if qx < 1.0 || qy < 1.0 || qx >= (sw - 1) as f32 || qy >= (sh - 1) as f32 {
                    continue;
                }
                ts[n] = grad_mag(target_rgb, tw, th, px, py);
                ss[n] = grad_mag(source_rgb, sw, sh, qx, qy);
                n += 1;
            }
        }
        if n < 8 {
            return f32::NEG_INFINITY;
        }
        let nn = n as f32;
        let mt = ts[..n].iter().sum::<f32>() / nn;
        let ms = ss[..n].iter().sum::<f32>() / nn;
        let (mut cov, mut vt, mut vs) = (0.0_f32, 0.0_f32, 0.0_f32);
        for k in 0..n {
            let a = ts[k] - mt;
            let b = ss[k] - ms;
            cov += a * b;
            vt += a * a;
            vs += b * b;
        }
        let den = (vt * vs).sqrt();
        if den < 1e-6 {
            0.0
        } else {
            cov / den
        }
    };
    let (mut dx, mut dy) = (0.0_f32, 0.0_f32);
    let mut best = score(0.0, 0.0);
    if !best.is_finite() {
        return (0.0, 0.0);
    }
    let mut step = max_disp * 0.5;
    for _ in 0..24 {
        let cands = [(dx + step, dy), (dx - step, dy), (dx, dy + step), (dx, dy - step)];
        let mut best_move: Option<(f32, f32, f32)> = None;
        for &(nx, ny) in cands.iter() {
            if nx * nx + ny * ny > max_disp * max_disp {
                continue;
            }
            let s = score(nx, ny);
            if s > best_move.map(|m| m.2).unwrap_or(best) {
                best_move = Some((nx, ny, s));
            }
        }
        if let Some((nx, ny, s)) = best_move {
            dx = nx;
            dy = ny;
            best = s;
        } else {
            step *= 0.5;
            if step < max_disp * 0.05 {
                break;
            }
        }
    }
    (dx, dy)
}

/// Local "spill" refinement: after the global similarity settles, fit a coarse
/// control grid of small source-pixel offsets, each found by vibrating a local
/// translation (`fit_local_offset`) to raise structure-NCC in its own
/// neighborhood. The bilinearly-interpolated field seats features where the two
/// faces disagree and leaves matched regions alone. Bounded per cell
/// (`≤ 0.06·interocular`) so it seats features without morphing identity, and
/// GATED globally: returns `None` unless the field raises whole-face NCC.
/// Returns `(field, global_gain, max_disp)`.
#[allow(clippy::too_many_arguments)]
fn local_spill(
    sim: &SimilarityMap,
    source_rgb: &[f32],
    sw: usize,
    sh: usize,
    target_rgb: &[f32],
    tw: usize,
    th: usize,
    face: FaceSwapBox,
    d: f32,
    strength: f32,
) -> Option<(SpillField, f32, f32)> {
    if strength <= 0.0 || sw < 3 || sh < 3 || face.w < 8.0 || face.h < 8.0 {
        return None;
    }
    const NX: usize = 4;
    const NY: usize = 4;
    let d = d.max(1.0);
    let max_disp = 0.06 * d;
    let half_x = (face.w / (NX as f32 - 1.0)) * 0.75;
    let half_y = (face.h / (NY as f32 - 1.0)) * 0.75;
    let mut dx = vec![0.0_f32; NX * NY];
    let mut dy = vec![0.0_f32; NX * NY];
    for j in 0..NY {
        for i in 0..NX {
            let u = i as f32 / (NX as f32 - 1.0);
            let v = j as f32 / (NY as f32 - 1.0);
            let cx = face.x + u * face.w;
            let cy = face.y + v * face.h;
            let (bdx, bdy) = fit_local_offset(
                sim, source_rgb, sw, sh, target_rgb, tw, th, cx, cy, half_x, half_y, max_disp,
            );
            dx[j * NX + i] = bdx;
            dy[j * NX + i] = bdy;
        }
    }
    let field = SpillField {
        nx: NX,
        ny: NY,
        face,
        dx,
        dy,
        strength: strength.clamp(0.0, 1.0),
    };
    // Global gate: keep the field only if it raises whole-face structure-NCC.
    let base = structure_ncc(sim, None, source_rgb, sw, sh, target_rgb, tw, th, face, 28);
    let after = structure_ncc(sim, Some(&field), source_rgb, sw, sh, target_rgb, tw, th, face, 28);
    if !base.is_finite() || !after.is_finite() || after <= base + 1e-4 {
        return None;
    }
    let max_disp_applied = field.max_disp();
    Some((field, after - base, max_disp_applied))
}

/// Residual non-rigid displacement (pixels) on top of the similarity base map,
/// from observed anchor correspondences only. Distances normalized by the
/// target interocular distance so behavior is scale-free.
#[allow(clippy::too_many_arguments)]
fn residual_idw_offset(
    px: f32,
    py: f32,
    sim: &SimilarityMap,
    source_anchors: &[FaceSwapAnchor],
    target_anchors: &[FaceSwapAnchor],
    confidence_floor: f32,
    target_d: f32,
) -> (f32, f32, f32) {
    let mut du_sum = 0.0_f32;
    let mut dv_sum = 0.0_f32;
    let mut weight_sum = 0.0_f32;
    let mut support = 0.0_f32;
    let mut observed = 0.0_f32;
    let d2_norm = (target_d * target_d).max(1.0);
    for role in [0_u8, 1, 2, 3, 4, 5, 6] {
        let role_weight = similarity_role_weight(role);
        if role_weight <= 0.0 {
            continue;
        }
        let Some((tx, ty, tc)) = best_anchor_for_role(target_anchors, role) else {
            continue;
        };
        let Some((sx, sy, sc)) = best_anchor_for_role(source_anchors, role) else {
            continue;
        };
        if tc < confidence_floor || sc < confidence_floor {
            continue;
        }
        let conf = (sc * tc).sqrt().clamp(0.0, 1.0);
        let (bx, by) = sim.apply(tx, ty);
        let rx = sx - bx;
        let ry = sy - by;
        let dx = px - tx;
        let dy = py - ty;
        let local = 1.0 / (0.15 + (dx * dx + dy * dy) / d2_norm);
        let weight = local * conf * conf * role_weight;
        du_sum += rx * weight;
        dv_sum += ry * weight;
        weight_sum += weight;
        support += conf * local.min(1.0);
        observed += 1.0;
    }
    if weight_sum <= 0.0 {
        return (0.0, 0.0, 0.0);
    }
    let strength = (weight_sum / (weight_sum + 3.0)).clamp(0.0, 0.78);
    let mut du = du_sum / weight_sum * strength;
    let mut dv = dv_sum / weight_sum * strength;
    let mag = (du * du + dv * dv).sqrt();
    let cap = 0.35 * target_d;
    if mag > cap {
        du *= cap / mag;
        dv *= cap / mag;
    }
    (du, dv, (support / observed.max(1.0)).clamp(0.0, 1.0))
}

fn source_sample_gate(u: f32, v: f32, source_frame: AnchorFaceFrame) -> f32 {
    let (cx, cy, rx, ry, support) = if source_frame.confidence >= 0.18 {
        (
            source_frame.cx,
            source_frame.cy - source_frame.ry * 0.06,
            source_frame.rx * 1.02,
            source_frame.ry * 1.04,
            source_frame.confidence,
        )
    } else {
        (0.5, 0.45, 0.5, 0.52, 0.0)
    };
    let dx = (u - cx) / rx.max(1e-3);
    let dy = (v - cy) / ry.max(1e-3);
    let ellipse = dx * dx + dy * dy;
    if ellipse >= 1.18 {
        return 0.0;
    }
    let oval = (1.0 - (ellipse / 1.18).clamp(0.0, 1.0)).sqrt();
    // Even when the detector box contains neck, collar, or torso, the source
    // sampler should not admit those pixels into the face texture warp.
    let lower_guard = 1.0 - smoothstep(0.76, 0.92, v);
    let upper_guard = smoothstep(-0.08, 0.06, v);
    (oval * lower_guard * upper_guard * (0.78 + support * 0.22)).clamp(0.0, 1.0)
}

fn feature_preservation_gate(
    u: f32,
    v: f32,
    target_face: FaceSwapBox,
    target_anchors: &[FaceSwapAnchor],
) -> f32 {
    let mut gate = 1.0_f32;
    for anchor in target_anchors {
        let Some((tu, tv, role, conf)) = normalized_anchor(*anchor, target_face) else {
            continue;
        };
        let (rx, ry, max_cut) = match role {
            0 | 1 => (0.12, 0.075, 0.7),
            3 | 4 | 5 => (0.18, 0.09, 0.62),
            9 | 10 => (0.14, 0.06, 0.38),
            _ => continue,
        };
        let dx = (u - tu) / rx;
        let dy = (v - tv) / ry;
        let d2 = dx * dx + dy * dy;
        if d2 < 1.0 {
            let cut = (1.0 - d2).powf(1.4) * max_cut * conf.clamp(0.0, 1.0);
            gate *= (1.0 - cut).clamp(0.18, 1.0);
        }
    }
    gate
}

fn anchor_count(source_anchors: &[FaceSwapAnchor], target_anchors: &[FaceSwapAnchor]) -> u32 {
    source_anchors
        .iter()
        .filter(|anchor| target_anchors.iter().any(|other| other.role == anchor.role))
        .count()
        .min(u32::MAX as usize) as u32
}

