    fn anchor(x: f32, y: f32, role: u8, confidence: f32) -> FaceSwapAnchor {
        FaceSwapAnchor { x, y, role, confidence }
    }

    /// Frontal anchor set for a face whose eyes sit at the given midpoint with
    /// the given interocular distance.
    fn frontal_anchors(mid_x: f32, mid_y: f32, d: f32) -> Vec<FaceSwapAnchor> {
        vec![
            anchor(mid_x - d * 0.5, mid_y, 0, 0.9),
            anchor(mid_x + d * 0.5, mid_y, 1, 0.9),
            anchor(mid_x, mid_y + d * 0.5, 2, 0.85),
            anchor(mid_x, mid_y + d * 0.9, 3, 0.8),
        ]
    }

    /// The bug this file was rewritten for: a loose detector box (full frame)
    /// must not drag the matte down onto the collar/chest. The eye bar, not
    /// the box, decides where the transfer lands.
    #[test]
    fn loose_target_box_keeps_transfer_on_face() {
        let source = rgb_fixture(64, 64, [0.9, 0.3, 0.25], [0.85, 0.28, 0.22]);
        let target = rgb_fixture(64, 96, [0.15, 0.25, 0.8], [0.15, 0.25, 0.8]);
        let source_face = FaceSwapBox { x: 8.0, y: 8.0, w: 48.0, h: 48.0 };
        // Deliberately loose: the whole frame. The face lives in the top third.
        let target_face = FaceSwapBox { x: 0.0, y: 0.0, w: 64.0, h: 96.0 };
        let source_anchors = frontal_anchors(32.0, 28.0, 16.0);
        let target_anchors = frontal_anchors(32.0, 16.0, 16.0);

        let result = face_to_face_swap_rgb_f32_v3(
            &source,
            64,
            64,
            &target,
            64,
            96,
            source_face,
            target_face,
            FaceSwapLandmarks::default(),
            FaceSwapLandmarks::default(),
            &source_anchors,
            &target_anchors,
            &FaceSwapV3Params::default(),
            None,
            &FaceToFaceSwapConfig::default(),
        )
        .unwrap();

        assert!(result.certificate.accepted, "reason: {}", result.certificate.reason);
        assert_eq!(result.certificate.target_matte_mode, "eye_bar");
        let mut weighted_y = 0.0_f32;
        let mut alpha_total = 0.0_f32;
        for y in 0..96_usize {
            for x in 0..64_usize {
                let a = result.alpha[y * 64 + x];
                weighted_y += a * y as f32;
                alpha_total += a;
                if y as f32 > 96.0 * 0.6 {
                    assert_eq!(a, 0.0, "alpha painted at collar/chest row {}", y);
                }
            }
        }
        assert!(alpha_total > 0.0);
        let centroid_y = weighted_y / alpha_total;
        assert!(
            centroid_y < 96.0 * 0.45,
            "matte centroid landed low: {} (loose box dragged the oval down)",
            centroid_y
        );
    }

    #[test]
    fn similarity_fit_recovers_synthetic_transform() {
        let scale = 1.4_f32;
        let theta = 0.3_f32;
        let (mtx, mty) = (30.0_f32, 26.0_f32);
        let (msx, msy) = (52.0_f32, 40.0_f32);
        let target_points = [
            (22.0, 24.0, 0_u8),
            (38.0, 24.0, 1),
            (30.0, 32.0, 2),
            (30.0, 38.0, 3),
            (30.0, 46.0, 6),
        ];
        let mut source_anchors = Vec::new();
        let mut target_anchors = Vec::new();
        for (x, y, role) in target_points {
            let dx = x - mtx;
            let dy = y - mty;
            let sx = msx + scale * (theta.cos() * dx - theta.sin() * dy);
            let sy = msy + scale * (theta.sin() * dx + theta.cos() * dy);
            target_anchors.push(anchor(x, y, role, 0.9));
            source_anchors.push(anchor(sx, sy, role, 0.9));
        }
        let sim = fit_similarity(&source_anchors, &target_anchors, 0.4, 4.0)
            .expect("similarity should fit");
        assert!((sim.scale() - scale).abs() < 1e-3, "scale {}", sim.scale());
        assert!((sim.rotation() - theta).abs() < 1e-3, "rotation {}", sim.rotation());
    }

    #[test]
    fn micro_refine_recovers_a_perturbed_fit_and_never_worsens() {
        // Build a small structured target (bright cross on dark) and an identical
        // source. The exact identity map maximizes structure-NCC. A perturbed map
        // (shifted a few px) should be pulled back toward identity, RAISING the
        // score; and refining the ALREADY-exact map must not lower it (gated).
        let (w, h) = (64usize, 64usize);
        let mut img = vec![0.0f32; w * h * 3];
        // Rich, asymmetric texture => a UNIQUE structure-NCC peak at zero shift
        // (a sparse/symmetric pattern is ambiguous under translation).
        for y in 0..h {
            for x in 0..w {
                let (xf, yf) = (x as f32, y as f32);
                let v = 0.5
                    + 0.30 * (xf * 0.7).sin() * (yf * 0.5).cos()
                    + 0.15 * (xf * 0.31 + yf * 0.93).sin()
                    + 0.05 * (yf * 1.7).cos();
                for c in 0..3 {
                    img[(y * w + x) * 3 + c] = v.clamp(0.0, 1.0);
                }
            }
        }
        let face = FaceSwapBox { x: 12.0, y: 12.0, w: 40.0, h: 40.0 };
        let identity = SimilarityMap {
            mu_tx: 32.0,
            mu_ty: 32.0,
            mu_sx: 32.0,
            mu_sy: 32.0,
            a: 1.0,
            b: 0.0,
            confidence: 0.9,
        };
        // Perturbed by a 3px translation — refine should recover most of it.
        let perturbed = SimilarityMap { mu_sx: 35.0, mu_sy: 33.0, ..identity };
        let base = structure_ncc(&perturbed, None, &img, w, h, &img, w, h, face, 24);
        let (refined, gain) = micro_refine(perturbed, &img, w, h, &img, w, h, face, 24.0);
        assert!(gain >= 0.0, "gain must never be negative (gated), got {}", gain);
        let after = structure_ncc(&refined, None, &img, w, h, &img, w, h, face, 24);
        assert!(after >= base - 1e-6, "refine worsened alignment: {} -> {}", base, after);
        assert!(
            (refined.mu_sx - 32.0).abs() < (perturbed.mu_sx - 32.0).abs(),
            "refine did not pull translation back toward truth: {} (from 35, truth 32)",
            refined.mu_sx
        );
        // Refining the exact fit must not drift it (gate holds).
        let (_r2, gain2) = micro_refine(identity, &img, w, h, &img, w, h, face, 24.0);
        assert!(gain2 >= 0.0 && gain2 < 0.05, "exact fit should barely move: gain {}", gain2);
    }

    #[test]
    fn local_spill_seats_a_regional_warp_and_is_gated() {
        // Target: rich texture. Source: same texture but with the LEFT half
        // shifted +4px in x (a regional mismatch a rigid map can't fix — one half
        // aligns, the other doesn't). Local spill should warp the mismatched half
        // back and RAISE structure-NCC; and with strength 0 it must return None.
        let (w, h) = (72usize, 72usize);
        let tex = |x: f32, y: f32| -> f32 {
            (0.5 + 0.30 * (x * 0.6).sin() * (y * 0.5).cos()
                + 0.15 * (x * 0.29 + y * 0.91).sin())
            .clamp(0.0, 1.0)
        };
        let mut target = vec![0.0f32; w * h * 3];
        let mut source = vec![0.0f32; w * h * 3];
        for y in 0..h {
            for x in 0..w {
                let tv = tex(x as f32, y as f32);
                // Source left half sampled 4px to the right -> regional offset.
                let shift = if x < w / 2 { 4.0 } else { 0.0 };
                let sv = tex(x as f32 + shift, y as f32);
                for c in 0..3 {
                    target[(y * w + x) * 3 + c] = tv;
                    source[(y * w + x) * 3 + c] = sv;
                }
            }
        }
        let face = FaceSwapBox { x: 10.0, y: 10.0, w: 52.0, h: 52.0 };
        let identity = SimilarityMap {
            mu_tx: 36.0, mu_ty: 36.0, mu_sx: 36.0, mu_sy: 36.0, a: 1.0, b: 0.0, confidence: 0.9,
        };
        let base = structure_ncc(&identity, None, &source, w, h, &target, w, h, face, 28);
        let out = local_spill(&identity, &source, w, h, &target, w, h, face, 24.0, 0.8);
        let (field, gain, max_disp) = out.expect("spill should find a helping warp");
        assert!(gain > 0.0, "spill gain must be positive, got {}", gain);
        assert!(max_disp > 0.0 && max_disp <= 0.06 * 24.0 + 1e-3, "disp bounded: {}", max_disp);
        let after = structure_ncc(&identity, Some(&field), &source, w, h, &target, w, h, face, 28);
        assert!(after > base, "spill did not raise NCC: {} -> {}", base, after);
        // strength 0 => disabled, no field.
        assert!(local_spill(&identity, &source, w, h, &target, w, h, face, 24.0, 0.0).is_none());
    }

    #[test]
    fn opposite_head_tilts_rotate_fully_not_clamped() {
        // Source head tilts +25 deg, target tilts -25 deg: aligning the eye bars
        // needs a 50 deg source rotation. The old 31.5 deg clamp under-rotated
        // this and left the swap visibly misaligned; the widened ~57 deg clamp
        // must let the honest rotation through.
        let d = 20.0_f32;
        let eyes = |cx: f32, cy: f32, deg: f32| {
            let (ex, ey) = (deg.to_radians().cos(), deg.to_radians().sin());
            vec![
                anchor(cx - ex * d / 2.0, cy - ey * d / 2.0, 0, 0.9),
                anchor(cx + ex * d / 2.0, cy + ey * d / 2.0, 1, 0.9),
            ]
        };
        let source_anchors = eyes(50.0, 50.0, 25.0);
        let target_anchors = eyes(30.0, 30.0, -25.0);
        let sim = fit_similarity(&source_anchors, &target_anchors, 0.4, 4.0)
            .expect("similarity should fit");
        let rot = sim.rotation();
        assert!(
            (rot - 50.0_f32.to_radians()).abs() < 1e-2,
            "opposite tilts should rotate ~50 deg, got {} deg (still clamped?)",
            rot.to_degrees()
        );
        assert!(
            rot.to_degrees() > 31.5,
            "rotation {} deg sits under the OLD clamp — the widen didn't take",
            rot.to_degrees()
        );
    }

    #[test]
    fn uv_round_trip_property() {
        let target_anchors = frontal_anchors(30.0, 26.0, 18.0);
        let mut source_anchors = Vec::new();
        // Pure translation + uniform scale of the same layout.
        for a in &target_anchors {
            source_anchors.push(anchor((a.x - 30.0) * 1.2 + 50.0, (a.y - 26.0) * 1.2 + 44.0, a.role, a.confidence));
        }
        let sim = fit_similarity(&source_anchors, &target_anchors, 0.4, 4.0)
            .expect("similarity should fit");
        for (t, s) in target_anchors.iter().zip(source_anchors.iter()) {
            let (qx, qy) = sim.apply(t.x, t.y);
            assert!(
                (qx - s.x).abs() < 1e-2 && (qy - s.y).abs() < 1e-2,
                "similarity misses anchor: ({}, {}) -> ({}, {}), expected ({}, {})",
                t.x, t.y, qx, qy, s.x, s.y
            );
            let (du, dv, _) = residual_idw_offset(
                t.x, t.y, &sim, &source_anchors, &target_anchors, 0.4, 18.0,
            );
            assert!(du.abs() < 1e-2 && dv.abs() < 1e-2, "residual should vanish on exact fit");
        }
    }

    #[test]
    fn rotated_matte_follows_eye_tilt() {
        let tilt = 20.0_f32.to_radians();
        let d = 16.0_f32;
        let (lx, ly) = (20.0_f32, 20.0_f32);
        let anchors = vec![
            anchor(lx, ly, 0, 0.9),
            anchor(lx + d * tilt.cos(), ly + d * tilt.sin(), 1, 0.9),
        ];
        let frame = eye_bar_frame(&anchors).expect("frame");
        let (cx, cy) = frame.center(EYE_BAR_CENTER_K);
        let r = EYE_BAR_RY * d * 0.7;
        // Along the rotated face-down axis vs the unrotated image-down axis.
        let along_rotated = eye_bar_matte(cx + frame.nx() * r, cy + frame.ny() * r, &frame);
        let along_image_down = eye_bar_matte(cx, cy + r, &frame);
        assert!(
            along_rotated > along_image_down,
            "matte did not rotate with the eye bar: rotated={} image_down={}",
            along_rotated,
            along_image_down
        );
    }

    #[test]
    fn reinhard_matches_target_stats() {
        // Nearly flat source, high-contrast target: v3 must widen the source
        // toward the target's variance (ratio clamps at 1.6).
        let source = rgb_fixture(64, 64, [0.5, 0.5, 0.5], [0.52, 0.52, 0.52]);
        let target = rgb_fixture(64, 64, [0.15, 0.15, 0.15], [0.85, 0.85, 0.85]);
        let source_face = FaceSwapBox { x: 8.0, y: 8.0, w: 48.0, h: 48.0 };
        let target_face = FaceSwapBox { x: 8.0, y: 8.0, w: 48.0, h: 48.0 };
        let result = face_to_face_swap_rgb_f32_v3(
            &source,
            64,
            64,
            &target,
            64,
            64,
            source_face,
            target_face,
            FaceSwapLandmarks::default(),
            FaceSwapLandmarks::default(),
            &frontal_anchors(32.0, 26.0, 16.0),
            &frontal_anchors(32.0, 26.0, 16.0),
            &FaceSwapV3Params::default(),
            None,
            &FaceToFaceSwapConfig::default(),
        )
        .unwrap();
        assert!(result.certificate.accepted, "reason: {}", result.certificate.reason);
        assert!(
            result.certificate.color_std_ratio >= 1.3,
            "std ratio not applied: {}",
            result.certificate.color_std_ratio
        );
    }

    #[test]
    fn temporal_ema_blends_frames() {
        let source = rgb_fixture(64, 64, [0.9, 0.3, 0.25], [0.85, 0.28, 0.22]);
        let target = rgb_fixture(64, 64, [0.15, 0.25, 0.8], [0.15, 0.25, 0.8]);
        let source_face = FaceSwapBox { x: 8.0, y: 8.0, w: 48.0, h: 48.0 };
        let target_face = FaceSwapBox { x: 4.0, y: 4.0, w: 56.0, h: 56.0 };
        let source_anchors = frontal_anchors(32.0, 28.0, 16.0);
        let target_anchors = frontal_anchors(32.0, 24.0, 16.0);
        let run = |prev: Option<PrevTargetFrame>, smoothing: f32| {
            let params = FaceSwapV3Params { temporal_smoothing: smoothing, ..Default::default() };
            face_to_face_swap_rgb_f32_v3(
                &source, 64, 64, &target, 64, 64, source_face, target_face,
                FaceSwapLandmarks::default(), FaceSwapLandmarks::default(),
                &source_anchors, &target_anchors, &params, prev,
                &FaceToFaceSwapConfig::default(),
            )
            .unwrap()
        };
        let instantaneous = run(None, 0.5).certificate.target_frame_cx;
        // Previous frame reports the eye midpoint far to the left.
        let prev: PrevTargetFrame = [0.25, 24.0 / 64.0, 16.0 / 64.0, 0.0, 0.0];
        let smoothed = run(Some(prev), 0.5).certificate.target_frame_cx;
        assert!(
            smoothed > prev[0] && smoothed < instantaneous,
            "EMA not blending: prev={} smoothed={} instant={}",
            prev[0],
            smoothed,
            instantaneous
        );
    }

    /// Opposite half-turns: the kernel must mirror the source so the target's
    /// visible half receives visible-half texture, and must fade the matte on
    /// the target's occluded side.
    #[test]
    fn opposite_profiles_mirror_source_and_fade_occluded_half() {
        let source = rgb_fixture(64, 64, [0.9, 0.3, 0.25], [0.85, 0.28, 0.22]);
        let target = rgb_fixture(64, 64, [0.15, 0.25, 0.8], [0.15, 0.25, 0.8]);
        let source_face = FaceSwapBox { x: 8.0, y: 8.0, w: 48.0, h: 48.0 };
        let target_face = FaceSwapBox { x: 8.0, y: 8.0, w: 48.0, h: 48.0 };
        // Source turned one way (nose pushed toward +e), target the other,
        // both in a genuine half-turn.
        let source_anchors = vec![
            anchor(24.0, 28.0, 0, 0.9),
            anchor(40.0, 28.0, 1, 0.9),
            anchor(36.8, 36.0, 2, 0.85), // nose offset +4.8 = yaw +0.6
            anchor(32.0, 42.0, 3, 0.8),
        ];
        let target_anchors = vec![
            anchor(24.0, 26.0, 0, 0.9),
            anchor(40.0, 26.0, 1, 0.9),
            anchor(27.2, 34.0, 2, 0.85), // nose offset -4.8 = yaw -0.6
            anchor(32.0, 40.0, 3, 0.8),
        ];
        let result = face_to_face_swap_rgb_f32_v3(
            &source, 64, 64, &target, 64, 64, source_face, target_face,
            FaceSwapLandmarks::default(), FaceSwapLandmarks::default(),
            &source_anchors, &target_anchors,
            &FaceSwapV3Params::default(), None,
            &FaceToFaceSwapConfig::default(),
        )
        .unwrap();
        assert!(result.certificate.source_mirrored, "opposite yaws must mirror the source");
        assert!(result.certificate.target_frame_yaw < -0.4);
        assert!(result.certificate.source_frame_yaw > 0.4);
        // Occluded target half (nose points toward -e = image left) must carry
        // less alpha than the visible half.
        let mut left_alpha = 0.0_f32;
        let mut right_alpha = 0.0_f32;
        for y in 0..64_usize {
            for x in 0..64_usize {
                let a = result.alpha[y * 64 + x];
                if (x as f32) < 32.0 {
                    left_alpha += a;
                } else {
                    right_alpha += a;
                }
            }
        }
        assert!(
            left_alpha < right_alpha * 0.5,
            "occluded half not faded: left={} right={}",
            left_alpha,
            right_alpha
        );
    }

    /// Regression test for a real production bug: with a large size gap
    /// between the source and target photos (e.g. a small reference photo
    /// swapped onto a zoomed-in target frame), `fit_similarity` used to clamp
    /// the fitted scale to a fixed absolute band (`scale.clamp(0.5, 2.2)`),
    /// overriding an otherwise-correct anchor-derived scale. That silently
    /// distorted the target->source mapping so every pixel below the eye
    /// line sampled too far down in the source -- landing on the neck/collar
    /// even though the eye landmarks were correctly detected on both faces.
    /// The clamp is now a wide numerical-blowup guard, not a plausibility
    /// window, so the fit tracks the true (anchor-derived) ratio.
    #[test]
    fn large_size_mismatch_does_not_overreach_into_source_neck() {
        // Source: small face, d=20, eyes at (40,50)/(60,50), mid (50,50).
        let source_anchors = vec![anchor(40.0, 50.0, 0, 0.92), anchor(60.0, 50.0, 1, 0.92)];
        // Target: same face, 10x bigger, d=200, mid (400,300).
        let target_anchors = vec![anchor(300.0, 300.0, 0, 0.92), anchor(500.0, 300.0, 1, 0.92)];
        let target_frame = eye_bar_frame(&target_anchors).expect("target eye bar");
        let reference_spread = target_frame.d * 0.35;
        let sim = fit_similarity(&source_anchors, &target_anchors, 0.4, reference_spread)
            .expect("similarity should fit from 2 eye anchors");

        let true_scale = 20.0_f32 / 200.0_f32; // 0.1
        assert!(
            (sim.scale() - true_scale).abs() < 1e-4,
            "fitted scale should track the true anchor-derived ratio, got fitted={} true={}",
            sim.scale(),
            true_scale
        );

        let v3 = V3Context {
            params: FaceSwapV3Params::default(),
            source_frame: eye_bar_frame(&source_anchors),
            target_frame: Some(target_frame),
            similarity: Some(sim),
            mirrored: false,
            micro_refine_gain: 0.0,
            spill: None,
            spill_gain: 0.0,
            spill_max_disp: 0.0,
        };

        // Target pixels at the nose (0.5d below eye line), mouth (0.95d) and
        // chin (1.35d), scaled to the target's own d=200, must land on the
        // matching source anatomy (source d=20) rather than overshooting
        // past the source chin (77) into background/neck territory.
        let probes = [
            ("nose", 400.0_f32, 400.0_f32, 60.0_f32),
            ("mouth", 400.0_f32, 490.0_f32, 69.0_f32),
            ("chin", 400.0_f32, 570.0_f32, 77.0_f32),
        ];
        for (label, px, py, expected_sy) in probes {
            let (_qx, qy, gate, _support) =
                v3_source_sample(px, py, &v3, &source_anchors, &target_anchors)
                    .unwrap_or_else(|| panic!("v3 sample missing for {label}"));
            assert!(
                (qy - expected_sy).abs() < 1.0,
                "{label}: expected source y ~= {expected_sy}, got {qy}"
            );
            assert!(gate > 0.1, "{label}: source sample gated out (qy={qy}, gate={gate})");
        }
    }
